# Generated by google (gemini-2.5-flash)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: 'echo "No custom build command specified. Skipping build."', description: 'Custom shell command for the build step. Example: mvn clean install')
        string(name: 'TEST_COMMAND', defaultValue: 'echo "No custom test command specified. Skipping tests."', description: 'Custom shell command for the test step. Example: mvn test')
        string(name: 'DEPLOY_COMMAND', defaultValue: 'echo "No custom deploy command specified. Skipping deployment."', description: 'Custom shell command for the deployment step. Example: docker push my-image:latest')
    }

    stages {
        stage('Build') {
            steps {
                echo "Executing custom build command: ${params.BUILD_COMMAND}"
                sh "${params.BUILD_COMMAND}"
            }
        }
        stage('Test') {
            steps {
                echo "Executing custom test command: ${params.TEST_COMMAND}"
                sh "${params.TEST_COMMAND}"
            }
        }
        stage('Deploy') {
            steps {
                echo "Executing custom deployment command: ${params.DEPLOY_COMMAND}"
                sh "${params.DEPLOY_COMMAND}"
            }
        }
    }
}